    t_thue: ['t_thue', 'thue'],

    t_tt_nt: '[t_tt_nt]:=[t_tien_nt0]+[t_cp_nt]+[t_nk_nt]+[t_ttdb_nt]&EnvironmentTaxExecuteExpressionFC;+[t_thue_nt]',
    t_tt: '[t_tt]:=[t_tien0]+[t_cp]+[t_nk]+[t_ttdb]+[t_thue]&EnvironmentTaxExecuteExpression;'
